function between(e,n,r){return n&&e<n?n:r&&r<e?r:e}function isValidNumber(e){return null!==e&&!1!==e&&!Number.isNaN(Number(e))}function safeMin(){for(var e=[],n=0;n<arguments.length;n++)e[n]=arguments[n];return Math.min.apply(Math,e.filter(isValidNumber))}function safeMax(){for(var e=[],n=0;n<arguments.length;n++)e[n]=arguments[n];return Math.max.apply(Math,e.filter(isValidNumber))}export{between,safeMin,safeMax};